VALUES
  ('social-worker-moex-01361', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關Reamer倫理抉擇原則的敘述，下列何者正確？', '["個人的自由權優先於另一個人的基本幸福權", "防止傷害人們生存行動必要先決條件規則優先於說謊解密威脅的規則", "個人的基本幸福權應優先於他自己的自由權", "在衝突的時候，個人自由權是超越法律安排"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01362', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '依據社會工作倫理的要求，有關保密的作法，下列何者正確？', '["當案主未成年又涉及性侵家暴等議題，仍要取得案主同意方能進行通報，才算保密", "社會工作者必須將問題處理的不同方式分析給案主知道，再讓案主做決定，才算保密", "社會工作者在一般情況下，必須要徵得案主授權才能將案主的紀錄予以複製，才算保密", "即使個案允許，社會工作者都不得將雙方之會談內容告知第三者，才算保密"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01363', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會團體工作中的「團體」的定義，下列何者錯誤？', '["團體具動態的本質，其中任何一部分的改變，都會影響其他部分", "團體是一個有生命，會產生變化，具有形或無形的界限和範圍的有機體", "團體不會隨時間進展而改變", "團體是指兩人或兩人以上的成員聚集在一起，透過互動，為追求共同目標而努力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01364', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關不同類型任務性團體的組成，下列何者正確？', '["「顧問團」的組成是基於行政責任及專長而被委派", "「委員會」的組成主要是挑選具類似教育專長的個人", "「董事會」的組成主要是同質性的考量，以協助決策的制定", "「社會行動團體」的成員組成通常是異質性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01365', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當工作者或其他團體成員在發表意見時，團體中有位成員與另一位成員經常在竊竊私語，而每當 有此種情況發生時，工作者以負向批評的語言加以反應。幾次之後，即使成員只是轉頭並未說話， 但工作者仍以負向言語加以回應。前述情況可以用下列何者解釋？', '["認知行為理論", "社會學習理論", "操作制約", "古典制約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01366', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社會團體工作理論的敘述，下列何者錯誤？', '["藉著了解成員的生命故事，得以找到增強的力量，以面對艱困的處境，所以充權、結構和敘事 三個理論觀點有很強的關聯", "將焦點放在失能與問題，再加充權和優勢觀點，讓成員找到解決問題和適應艱困環境的因應技巧", "處遇性團體的成員常有許多充滿著問題的故事，這些故事形塑出成員的生命圖像，深深地影響 成員的自我概念和自尊", "充權、結構和敘事這些理論強調要了解成員的獨特性和主體性，以及社會工作長久以來一直強 調的「從案主的立場來看」的觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01367', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體動力學研究內容包含的變項，下列何者錯誤？', '["成員改變", "團體發展", "輸入和產出", "統合運作過程"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01368', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「以和為貴」的社會文化，限制了人際衝突的「檯面化」；表面看似「和諧」的團體現象，底下 卻是「波濤洶湧」，這兩種情況說明下列何者現象？', '["團體動力有助於預防及處理個體在各個階段所面臨的問題", "團體動力有利於了解團體「表象」下的「真相」", "團體動力的理念與技術是在協助團體組織發展與變革", "團體動力影響團體運作的力量，與團體輔導實務息息相關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01369', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關團體工作的歷史發展，下列何者正確？①1950年代及1960年代，在鄰里中心及社區機構運用', '["1960年代社會工作學院實務朝向綜融觀點發展，導致 團體工作方法蓬勃發展", "1930年代至1940年代間，影響團體工作發展的兩大議題，一為對貧窮 作戰，一為公民權利運動", "1980年代及1990年代，社會團體工作促進協會（AASWG）透過辦 理專題研討會、促進團體工作課程之規劃、發展團體工作教育的標準等，試圖復興社會團體工作， 持續且不斷地增加 ⑤社會個案工作的先驅MaryRichmond於1920年代開始注意到小團體心理學", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01370', 'social-worker', 'social-worker-moex-109-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '領導行為是一個複雜的人際歷程，領導者與成員之間所蘊含的互動內涵，下列何者錯誤？', '["互惠（reciprocal）", "分配（distributional）", "轉化（transformational）", "交流（transactional）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "e697d89d6b44", "answer_pdf_sha1": "6638e1fe6f90", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
